srcDoc.css:
#container {
  position: relative;
  width: 100%;
}

#base {
  width: 100%;
  display: block;
}

#overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  pointer-events: none;
}

#base,
#overlay {
  width: 80%;
  margin-left: 10%;
}

srcDoc.js:
function renderOverlays() {
  const container = document.getElementById("overlays");
  container.innerHTML = "";
  (appsmith.model.overlays || []).forEach(url => {
    const img = document.createElement("img");
    img.src = url;
    img.style.position = "absolute";
    img.style.top = "0";
    img.style.left = "0";
    img.style.width = "80%";
    img.style.marginLeft = "10%";
    img.style.pointerEvents = "none";
    container.appendChild(img);
  });
}
appsmith.onReady(() => {
  renderOverlays();
});
appsmith.onModelChange(() => {
  renderOverlays();
});

